# Add flag_emoji based on code
for country in countries:
    code = country['code'].lower()
    if code == 'xk':
        country['flag_emoji'] = '🇽🇰'
    else:
        try:
            flag_emoji = chr(ord(country['code'][0]) + 127397) + chr(ord(country['code'][1]) + 127397)
            country['flag_emoji'] = flag_emoji
        except:
            country['flag_emoji'] = '🏳️'

data = {
    "last_updated": "2026-04-02",
    "source": "Passport Index + Henley Passport Index",
    "turkish_passport": {
        "rank_henley": 53,
        "rank_passport_index": 51,
        "visa_free_count": 0,
        "visa_on_arrival_count": 0,
        "e_visa_count": 0,
        "visa_required_count": 0,
        "total_destinations": 0
    },
    "countries": countries
}

# Calculate counts
vf = len([c for c in countries if c['visa_status'] == 'visa_free'])
voa = len([c for c in countries if c['visa_status'] == 'visa_on_arrival'])
ev = len([c for c in countries if c['visa_status'] == 'e_visa'])
vr = len([c for c in countries if c['visa_status'] == 'visa_required'])
data['turkish_passport']['visa_free_count'] = vf
data['turkish_passport']['visa_on_arrival_count'] = voa
data['turkish_passport']['e_visa_count'] = ev
data['turkish_passport']['visa_required_count'] = vr
data['turkish_passport']['total_destinations'] = len(countries)

output_path = os.path.join(DATA_DIR, 'passport_data.json')
with open(output_path, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f"passport_data.json created with {len(countries)} countries")
print(f"  Visa-free: {vf}")
print(f"  Visa on arrival: {voa}")
print(f"  E-visa: {ev}")
print(f"  Visa required: {vr}")
